const chart = new Chart(document.getElementById('compChart'), {
  type: 'line',
  data: { labels: dates, datasets },
  options: {
    responsive: true,
    maintainAspectRatio: false,
    interaction: { mode: 'index', intersect: false },
    plugins: {
      legend: { display: false },
      tooltip: {
        backgroundColor: 'rgba(8,8,8,0.94)',
        borderColor: 'rgba(214,174,61,0.28)',
        borderWidth: 1,
        titleColor: '#f0cd68',
        bodyColor: '#f3ece0',
        padding: 10,
        callbacks: {
          label: ctx => {
            const v = ctx.parsed.y;
            const ret = (v - 100).toFixed(2);
            const sign = ret >= 0 ? '+' : '';
            return ` ${ctx.dataset.label}: ${v.toFixed(2)} (${sign}${ret}%)`;
          }
        }
      }
    },
    scales: {
      x: {
        ticks: { color: '#8c7d61', maxTicksLimit: 8 },
        grid: { color: 'rgba(255,255,255,0.04)' }
      },
      y: {
        ticks: {
          color: '#8c7d61',
          callback: v => v.toFixed(0)
        },
        grid: { color: 'rgba(255,255,255,0.06)' }
      }
    }
  }
});

// Legend toggle buttons
const btnRow = document.getElementById('legendBtns');
datasets.forEach((ds, i) => {
  const btn = document.createElement('button');
  btn.className = 'toggle-btn';
  btn.textContent = ds.label;
  btn.style.borderColor = ds.borderColor;
  btn.style.color = ds.borderColor;
  btn.onclick = () => {
    const meta = chart.getDatasetMeta(i);
    meta.hidden = !meta.hidden;
    btn.classList.toggle('hidden', meta.hidden);
    chart.update();
  };
  btnRow.appendChild(btn);
});



